var rotateGrid = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const g = grid.map(row => row.slice());
    const layers = Math.floor(Math.min(m, n) / 2);
    for (let layer = 0; layer < layers; layer++) {
        const top = layer, bottom = m - 1 - layer;
        const left = layer, right = n - 1 - layer;
        const coords = [];
        for (let c = left; c <= right; c++) coords.push([top, c]);
        for (let r = top + 1; r <= bottom; r++) coords.push([r, right]);
        for (let c = right - 1; c >= left; c--) coords.push([bottom, c]);
        for (let r = bottom - 1; r > top; r--) coords.push([r, left]);
        const vals = coords.map(([r, c]) => g[r][c]);
        const L = vals.length;
        const s = k % L;
        const rotated = vals.slice(s).concat(vals.slice(0, s));
        for (let i = 0; i < coords.length; i++) {
            g[coords[i][0]][coords[i][1]] = rotated[i];
        }
    }
    return g;
};
